            centers[c] = (double*)malloc(4 * sizeof(double));
            for (int i = 0; i < 4; i++) {
                scanf("%lf", &centers[c][i]);
            }
        }
        // Calculate the minimum expected time
        double minTime = INFINITY;
        for (int mask = 0; mask < (1 << C); mask++) {
            if (__builtin_popcount(mask) != K) continue;
