            int* centersUsed = (int*)malloc(K * sizeof(int));
            int idx = 0;
            for (int c = 0; c < C; c++) {
                if ((mask & (1 << c)) != 0) {
                    centersUsed[idx++] = c;
                }
            }
            for (int k = 0; k < K; k++) {
                int c = centersUsed[k];
                double P = centers[c][0];
                double S = centers[c][1];
                double T = centers[c][2];
                double X = centers[c][3];
                time += fabs(X) / V;
                // Calculate the time it takes to crack the password
                double crackTime = 0;
                for (int p = 1; p <= P; p++) {
                    double connectionTime = (p - 1) * S;
                    double programTime = (N[k] / p) * T;
                    crackTime += connectionTime + programTime;
                }
                crackTime /= P;
                time += crackTime;
            }
            time += fabs(centers[centersUsed[K - 1]][3]) / V;
            minTime = fmin(minTime, time);
        }
        printf("%.6f\n", minTime);
        free(N);
        for (int c = 0; c < C; c++) {
            free(centers[c]);
        }
        free(centers);
    }
    return 0;
}

