    for (let c = 0; c < C; c++) {
        centers.push(readline().split(' ').map(Number));
    }
    // Calculate the minimum expected time
    let minTime = Infinity;
    for (let mask = 0; mask < (1 << C); mask++) {
        if (countBits(mask) !== K) continue;
        let time = 0;
        const centersUsed = [];
        let idx2 = 0;
        for (let c = 0; c < C; c++) {
            if ((mask & (1 << c)) !== 0) {
                centersUsed[idx2++] = c;
            }
        }
        for (let k = 0; k < K; k++) {
            const c = centersUsed[k];
            const [P, S, T, X] = centers[c];
            time += Math.abs(X) / V;
            // Calculate the time it takes to crack the password
            let crackTime = 0;
            for (let p = 1; p <= P; p++) {
                const connectionTime = (p - 1) * S;
                const programTime = (N[k] / p) * T;
                crackTime += connectionTime + programTime;
            }
            crackTime /= P;
            time += crackTime;
        }
        time += Math.abs(centers[centersUsed[K - 1]][3]) / V;
        minTime = Math.min(minTime, time);
    }
    console.log(minTime.toFixed(6));
}

function countBits(n) {
    let count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}
